function infT = fDutchPltInfV01(dat)%% create information text for plot%% infT = fDutchPltInfV01(dat)%% dat: data% infT: information text%% Function Dutch plot inf, ver.1% Kei Nakamura% Created on Tuesday, November 23rd 2010. % Modified on %% main bodyinfT{1} = ['chrg[pC]:',num2str(0.001*floor(1000*dat(4)))];infT{2} = ['enrg[mJ]:',num2str(0.001*floor(1000*dat(5)))];infT{3} = ['peakE[MeV]:',num2str(floor(dat(7)))];infT{4} = ['fwhmE[MeV]:',num2str(floor(dat(9)))];infT{5} = ['peakP[mm]:',num2str(floor(dat(11)))];infT{6} = ['fwhmS[mm]:',num2str(floor(dat(13)))];infT{7} = ['MinE[MeV]:',num2str(floor(dat(15)))];infT{8} = ['MaxE[MeV]:',num2str(floor(dat(16)))];
